{
  "formal_minutes": {
    "회의정보": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"]
    },
    "확정결정": [
      {
        "주제": "공개 릴리스 목표 시점",
        "결정": "스모크 테스트 통과 시 금요일 15:00 KST 공개 릴리스",
        "근거": "수요일 제안 이후, 스모크 테스트 선행 필요 의견 반영"
      },
      {
        "주제": "packageName 불일치 대응 원칙",
        "결정": "불일치 발생 시 먼저 패키지 설정을 점검하고, 계약(컨트랙트) 자체가 잘못된 경우에만 스크립트 검토",
        "근거": "ignore 처리 제안 논의 후 반려"
      }
    ],
    "반려제안": [
      {
        "제안": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "결론": "반려"
      }
    ],
    "내부스트레치목표": [
      {
        "항목": "수요일 릴리스",
        "성격": "내부 스트레치 목표(확정 일정 아님)"
      }
    ],
    "비결정사항": [
      {
        "항목": "README 설치 단계 검토",
        "내용": "목요일까지 가능하면 검토 제안이 있었으나 담당자 미지정"
      },
      {
        "항목": "Hara의 tarball 경로 점검 시점",
        "내용": "Minjun의 스모크 결과 공유 이후 수행, 정확한 마감 시각 미설정"
      }
    ],
    "리스크": [
      "tarball 경로 오류 시 릴리스 지연 가능",
      "README 설치 단계가 최신이 아니면 릴리스 노트가 사용자에게 오해를 줄 수 있음"
    ],
    "오픈질문": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 명시해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 검토",
      "due": "목요일(가능하면)",
      "status": "담당자 미지정",
      "source_certainty": "부분확정"
    },
    {
      "owner": "Hara",
      "task": "생성된 tarball 경로 점검(스모크 결과 공유 후)",
      "due": "미정",
      "status": "대기(선행조건: Minjun 결과 공유)",
      "source_certainty": "확정(시점/기한은 미확정)"
    }
  ],
  "followup_note": {
    "다음확인사항": [
      "금요일 10:00 KST 이전 Minjun 스모크 테스트 결과 수신 여부 확인",
      "금요일 12:00 KST 이전 Doyun의 action_items.md 트리아지 노트 작성 여부 확인",
      "스모크 결과 이후 Hara의 tarball 경로 점검 결과 확인",
      "README 설치 단계 검토 담당자 지정 필요",
      "최종 릴리스 승인 권한자 확정 필요",
      "릴리스 노트에 수요일 내부 스트레치 목표 기재 여부 결정 필요"
    ],
    "주의사항_비창작규칙": [
      "고객명/외부 파트너를 추가로 만들지 말 것",
      "예산 정보, 보안 사고, 프로덕션 장애, 법무 승인 요구를 만들지 말 것",
      "명시되지 않은 담당자/마감일을 임의 확정하지 말 것",
      "수요일 일정은 확정 릴리스가 아니라 내부 스트레치 목표로만 기록할 것"
    ]
  },
  "non_invention_rules": {
    "금지추가사실": [
      "customer",
      "budget",
      "security_incident",
      "production_outage",
      "legal_approval_requirement",
      "unnamed_owner",
      "unnamed_deadline"
    ],
    "작성원칙": [
      "인라인 공개 안전 합성 픽스처에 있는 사실만 사용",
      "확정 결정과 미결/반려/리스크/오픈질문을 분리 기록",
      "불확실 항목은 불확실 상태로 표시"
    ]
  }
}
